window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cosmetology"] = window.COURSE_LANG["cosmetology"] || {};
window.COURSE_LANG["cosmetology"]["es"] = [
  {"id":1,"q":"Para uso en un salón de California, un producto se considera desinfectante solo si está:","opts":["Cualquier aerosol de limpieza con aroma","Registrado ante la EPA de EE. UU. con actividad bactericida, fungicida y virucida demostrada","Alcohol común de cualquier tienda","Agua caliente del grifo"],"re":"California define un desinfectante como un producto registrado ante la EPA con actividad bactericida, fungicida y virucida demostrada, usado según la etiqueta."},
  {"id":2,"q":"Antes de poder desinfectar un implemento de metal, primero debe estar:","opts":["Limpiado con jabón y agua para quitar la suciedad visible","Congelado toda la noche","Envuelto en una toalla","Enjuagado solo en el propio desinfectante"],"re":"Los desinfectantes solo actúan sobre una superficie limpia, así que la suciedad visible debe quitarse con jabón y agua antes de sumergir."},
  {"id":3,"q":"El nivel de descontaminación que destruye TODA la vida microbiana, incluidas las esporas bacterianas, es:","opts":["Higienizar","Limpiar","Esterilización","Quitar el polvo"],"re":"La esterilización, como con un autoclave, destruye todos los microorganismos incluidas las esporas; es el nivel más alto de descontaminación."},
  {"id":4,"q":"Los implementos no eléctricos, como tijeras o alicates, se desinfectan correctamente:","opts":["Secándolos con un paño limpio","Poniéndolos en una caja de luz UV","Sosteniéndolos bajo el agua corriente","Sumergiéndolos por completo en un desinfectante bien preparado durante el tiempo de contacto de la etiqueta"],"re":"Las herramientas no eléctricas deben sumergirse por completo en un desinfectante registrado ante la EPA durante todo el tiempo de contacto indicado en la etiqueta."},
  {"id":5,"q":"Un artículo poroso de un solo uso, como un palillo de naranjo de madera o una lima de cartón, debe:","opts":["Desecharse tras un cliente (o entregarse a ese cliente)","Desinfectarse y reutilizarse con el siguiente cliente","Limpiarse con alcohol y reutilizarse","Hervirse y devolverse al cajón"],"re":"Los artículos porosos absorben líquidos y no pueden desinfectarse, así que son de un solo uso y deben desecharse o entregarse al cliente."},
  {"id":6,"q":"Una caja de luz UV en un salón se usa adecuadamente para:","opts":["Esterilizar implementos por completo","Reemplazar los desinfectantes químicos","Guardar implementos que ya fueron limpiados y desinfectados","Matar todos los virus al contacto"],"re":"Una caja UV no desinfecta ni esteriliza de forma confiable; solo sirve para guardar herramientas que ya fueron limpiadas y desinfectadas."},
  {"id":7,"q":"Si por accidente cortas a un cliente y aparecen unas gotas de sangre, primero debes:","opts":["Seguir trabajando e ignorarlo","Limpiarlo con una toalla compartida","Detener el servicio y ponerte guantes","Reutilizar la misma herramienta sin desinfectar"],"re":"Detente de inmediato y ponte guantes desechables antes de manipular cualquier sangre, para protegerte a ti y al cliente de patógenos transmitidos por la sangre."},
  {"id":8,"q":"Las toallas y capas sucias usadas con un cliente deben:","opts":["Guardarse en un recipiente cerrado o tapado hasta lavarlas","Doblarse de nuevo junto con la ropa limpia","Reutilizarse con el siguiente cliente para ahorrar lavado","Dejarse en una canasta abierta sobre el mostrador"],"re":"La ropa usada se guarda en un recipiente cerrado, a menudo etiquetado, apartada de la limpia, y se lava antes de reutilizarla."},
  {"id":9,"q":"En el corte de cabello, la sección que se usa para medir el largo del corte y contra la cual se cortan las demás secciones se llama:","opts":["Coronilla","Guía (línea guía)","Ápice","Cresta parietal"],"re":"La guía es la primera sección cortada; las secciones siguientes se peinan hacia ella y se cortan a su medida para un resultado uniforme."},
  {"id":10,"q":"Un corte recto de un solo largo se logra cortando el cabello con una elevación de:","opts":["180 grados","90 grados","45 grados","0 grados (sin elevación)"],"re":"Un corte recto usa 0 grados de elevación: el cabello se peina hacia abajo y se corta en el perímetro, dejando el máximo peso y un solo largo."},
  {"id":11,"q":"Sostener el cabello recto a 90 grados de la cabeza antes de cortar generalmente produce:","opts":["Una forma sólida de un solo largo","Una línea de perímetro más pesada","Ningún cambio en la forma","Capas uniformes"],"re":"Elevar una sección a 90 grados quita peso y crea capas uniformes del mismo largo por toda la cabeza."},
  {"id":12,"q":"A medida que la elevación del corte aumenta de 0 hacia 90 grados y más, el resultado es:","opts":["Más peso y una línea más recta","Más capas y menos peso","Ningún efecto en el corte","Un perímetro más ancho y pesado"],"re":"Las elevaciones bajas acumulan peso y líneas rectas; subir la elevación aumenta las capas y quita peso a la forma."},
  {"id":13,"q":"Una guía que permanece en una posición para que todas las secciones se lleven hacia ella es una:","opts":["Guía estacionaria","Guía móvil","Guía de navaja","Guía a mano alzada"],"re":"Una guía estacionaria (fija) se queda en su lugar y cada sección se peina hacia ella, produciendo más largo o graduación hacia las puntas."},
  {"id":14,"q":"Una guía móvil (que viaja) se usa más comúnmente para crear:","opts":["Un bob recto de un solo largo","Ninguna guía","Solo un perímetro sin navaja","Cortes en capas"],"re":"Una guía móvil avanza con cada sección nueva, manteniendo el largo uniforme, que es como se producen los cortes en capas."},
  {"id":15,"q":"En un servicio de estilizado térmico, ¿cuál describe el método más seguro con una herramienta caliente cerca del cuero cabelludo?","opts":["Presionar la herramienta directamente contra el cuero cabelludo","Usar el calor más alto con cada cliente","Usar un peine o protector para proteger el cuero cabelludo del contacto directo","Omitir cualquier protección contra el calor"],"re":"Un peine o protector entre la herramienta caliente y el cuero cabelludo protege la piel del cliente de quemaduras durante el estilizado térmico."},
  {"id":16,"q":"El cabello mojado puede estirarse y vuelve a su largo original gracias a enlaces que el agua rompe temporalmente; estos son:","opts":["Enlaces disulfuro","Enlaces peptídicos","Enlaces covalentes","Enlaces de hidrógeno"],"re":"Los enlaces de hidrógeno son enlaces laterales físicos que el agua o el calor rompen y que se reforman al secar, así funcionan los moldeados húmedos y el estilizado térmico."},
  {"id":17,"q":"Los enlaces laterales fuertes que dan forma al cabello y que solo se rompen con servicios químicos como las permanentes son:","opts":["Enlaces de hidrógeno","Enlaces salinos","Enlaces disulfuro","Enlaces de agua"],"re":"Los enlaces disulfuro (de cistina) son enlaces químicos fuertes; deben romperse y reformarse químicamente para cambiar de forma permanente la forma del cabello."},
  {"id":18,"q":"La capa intermedia del tallo del cabello, donde ocurren la mayoría de los cambios químicos de color y permanente, es la:","opts":["Cutícula","Corteza","Médula","Folículo"],"re":"La corteza constituye la mayor parte del tallo y contiene el pigmento y los enlaces, por eso es donde ocurren los cambios de color, permanente y alisado."},
  {"id":19,"q":"La capa protectora más externa del cabello, que debe abrirse para que entre el color permanente, es la:","opts":["Corteza","Médula","Cutícula","Papila"],"re":"La cutícula es la capa externa de escamas superpuestas; los productos alcalinos la hinchan y levantan para que el color llegue a la corteza."},
  {"id":20,"q":"En la escala de pH, una solución neutra tiene un pH de:","opts":["0","3","7","14"],"re":"La escala de pH va de 0 a 14; 7 es neutro, por debajo de 7 es ácido y por encima de 7 es alcalino."},
  {"id":21,"q":"El cabello y la piel sanos son naturalmente un poco:","opts":["Ácidos (alrededor de pH 4.5 a 5.5)","Fuertemente alcalinos (alrededor de pH 11)","Exactamente neutros (pH 7)","Sin ningún pH"],"re":"El pH natural del cabello y la piel es ligeramente ácido, cerca de 4.5 a 5.5, lo que mantiene la cutícula compacta y la barrera de la piel intacta."},
  {"id":22,"q":"En el color de cabello permanente, el revelador (agente oxidante) más común es:","opts":["Hidróxido de sodio","Acetona","Tioglicolato de amonio","Peróxido de hidrógeno"],"re":"El peróxido de hidrógeno es el revelador oxidante que aclara el pigmento natural y ayuda a formar el nuevo color en la corteza."},
  {"id":23,"q":"¿Un revelador de 20 volúmenes equivale aproximadamente a qué concentración de peróxido de hidrógeno?","opts":["3%","6%","20%","40%"],"re":"El volumen corresponde a la concentración: 10 vol = 3%, 20 vol = 6%, 30 vol = 9%, 40 vol = 12%."},
  {"id":24,"q":"En el círculo cromático, para neutralizar tonos amarillos no deseados, el estilista usa un matizador basado en el color complementario:","opts":["Verde","Naranja","Rojo","Violeta"],"re":"El violeta está frente al amarillo en el círculo cromático, así que un matizador con base violeta cancela los tonos amarillos no deseados."},
  {"id":25,"q":"En el sistema de niveles de color, el nivel 1 es negro y el nivel 10 es:","opts":["El rubio más claro","Un castaño medio","Rojo brillante","Otro tono de negro"],"re":"El sistema de niveles mide la profundidad de 1 (el más oscuro, negro) a 10 (el rubio pálido más claro); los números más altos son más claros."},
  {"id":26,"q":"La mayoría de las permanentes alcalinas (de onda fría) ablandan los enlaces disulfuro usando:","opts":["Peróxido de hidrógeno","Agua común","Hidróxido de sodio","Tioglicolato de amonio (una loción de ondulación tipo tio)"],"re":"Las ondas frías alcalinas usan tioglicolato de amonio para romper los enlaces disulfuro y poder remodelar el cabello alrededor de los bigudíes."},
  {"id":27,"q":"Después de envolver y procesar una permanente, el neutralizante (el segundo paso) sirve para:","opts":["Romper más enlaces disulfuro","Reformar los enlaces disulfuro en la nueva forma","Quitar todo el color del cabello","Arrancar la cutícula"],"re":"El neutralizante oxida el cabello para reconstruir los enlaces disulfuro, fijando el nuevo patrón de rizo en su lugar."},
  {"id":28,"q":"La capa más externa de la piel es la:","opts":["Dermis","Epidermis","Capa subcutánea","Capa reticular"],"re":"La epidermis es la capa fina y más externa de la piel y no tiene vasos sanguíneos propios."},
  {"id":29,"q":"La capa más profunda y gruesa de la piel que contiene vasos sanguíneos, nervios y colágeno es la:","opts":["Estrato córneo","Epidermis","Dermis","Cutícula"],"re":"La dermis está debajo de la epidermis y aloja vasos sanguíneos, terminaciones nerviosas, folículos pilosos, glándulas y fibras de colágeno."},
  {"id":30,"q":"Un movimiento de masaje suave y deslizante usado para iniciar y terminar un facial es:","opts":["Effleurage (rozamiento)","Petrissage (amasamiento)","Tapotement (percusión)","Fricción"],"re":"El effleurage es un movimiento de rozamiento suave y continuo aplicado con los dedos o las palmas; es calmante y relajante."},
  {"id":31,"q":"Un servicio facial NO debe realizarse cuando el cliente tiene:","opts":["Piel un poco seca","Algunas pecas leves","Piel normal","Una afección cutánea inflamada o infectada"],"re":"La piel inflamada, infectada o lastimada es una contraindicación; debe omitirse el servicio y remitir al cliente a un médico según corresponda."},
  {"id":32,"q":"Un punto negro, un folículo obstruido con sebo endurecido y células muertas, se llama técnicamente:","opts":["Milia","Comedón","Pápula","Mácula"],"re":"Un comedón abierto, comúnmente llamado punto negro, es un folículo obstruido con sebo y queratina que se oscurece al exponerse al aire."},
  {"id":33,"q":"El aceite natural de la piel, que lubrica la superficie y es producido por las glándulas sebáceas, es el:","opts":["Sebo","Melanina","Queratina","Colágeno"],"re":"El sebo es la secreción aceitosa de las glándulas sebáceas que lubrica la piel y el cabello y ayuda a formar la barrera protectora."},
  {"id":34,"q":"El pigmento que da color a la piel y al cabello es la:","opts":["Colágeno","Queratina","Melanina","Elastina"],"re":"La melanina, producida por los melanocitos, es el pigmento responsable del color de la piel, el cabello y los ojos."},
  {"id":35,"q":"Antes de un servicio químico como el color, la prueba que ayuda a detectar una alergia a un tinte derivado de anilina es la:","opts":["Prueba de mechón","Prueba de parche (predisposición)","Prueba de elasticidad","Prueba de porosidad"],"re":"La prueba de parche (predisposición) aplica una pequeña cantidad del tinte en la piel 24 a 48 horas antes del servicio para detectar una reacción alérgica."},
  {"id":36,"q":"La parte de la uña donde se forman las nuevas células y comienza el crecimiento es la:","opts":["Borde libre","Lecho ungueal","Matriz","Lúnula"],"re":"La matriz produce las células que forman la lámina ungueal; un daño en la matriz puede deformar la uña de forma permanente."},
  {"id":37,"q":"La forma blanquecina de media luna en la base de la uña es la:","opts":["Lúnula","Eponiquio","Hiponiquio","Borde libre"],"re":"La lúnula es la media luna visible y más clara en la base de la uña, que marca el final de la matriz bajo la lámina."},
  {"id":38,"q":"La parte de la lámina ungueal que se extiende más allá de la punta del dedo es el:","opts":["Lecho ungueal","Borde libre","Matriz","Cutícula"],"re":"El borde libre es la parte de la lámina ungueal que crece más allá de la punta del dedo y se recorta y da forma durante la manicura."},
  {"id":39,"q":"Un técnico de uñas NO debe realizar un servicio en una uña que muestre signos de:","opts":["Un borde libre largo","Esmalte aplicado recientemente","Estrías naturales por la edad","Infección, como enrojecimiento, pus u hongos"],"re":"Los signos de infección (enrojecimiento, hinchazón, pus u hongos) son contraindicaciones; debe remitirse al cliente a un médico y no atenderlo."},
  {"id":40,"q":"Una infección por hongos de la uña, que suele causar engrosamiento y decoloración, se llama:","opts":["Onicomicosis","Onicofagia","Leuconiquia","Padrastro"],"re":"La onicomicosis es una infección por hongos de la uña; es una afección médica y es una contraindicación para los servicios de uñas."},
  {"id":41,"q":"Después de una pedicura, el recipiente de la tina de pies debe limpiarse y hacer circular desinfectante por él durante al menos:","opts":["10 segundos","30 segundos","2 minutos","10 minutos"],"re":"California exige hacer circular un desinfectante hospitalario registrado ante la EPA y bien preparado por el recipiente durante al menos 10 minutos después de cada cliente."},
  {"id":42,"q":"Morderse las uñas habitualmente se conoce profesionalmente como:","opts":["Onicofagia","Onicomicosis","Pterigión","Onicólisis"],"re":"La onicofagia es el término técnico para el hábito de morderse las uñas, que puede dañar la uña y la piel circundante."},
  {"id":43,"q":"La acetona y muchos monómeros de uñas son inflamables, por lo que deben almacenarse:","opts":["Junto a una vela","Lejos del calor, las chispas y las llamas abiertas","En un plato abierto sobre el calentador","Al lado del gabinete de toallas calientes"],"re":"La acetona y los monómeros son inflamables; mantenlos tapados y lejos del calor, las chispas y las llamas abiertas para prevenir incendios."},
  {"id":44,"q":"La Junta de Barbería y Cosmetología de California opera bajo el/la:","opts":["Departamento de Asuntos del Consumidor","OSHA federal","Departamento de Agricultura de EE. UU.","Comisión Federal de Comercio"],"re":"La Junta forma parte del Departamento de Asuntos del Consumidor de California, que supervisa los programas de licencias del estado."},
  {"id":45,"q":"En California, una licencia de cosmetología o barbería generalmente debe renovarse:","opts":["Cada seis meses","Una sola vez y nunca más","Cada dos años","Solo después de mudarse"],"re":"Las licencias de cosmetología y afines de California se renuevan en un ciclo de dos años a través del Departamento de Asuntos del Consumidor."},
  {"id":46,"q":"Un salón que ofrece servicios regulados por la Junta debe tener, además de la licencia de cada profesional, una:","opts":["Permiso de estacionamiento","Licencia de establecimiento (salón)","Suscripción a una revista","Tarjeta de la biblioteca municipal"],"re":"Se requiere una licencia de establecimiento para un negocio que ofrece servicios regulados por la Junta, junto con las licencias de los profesionales."},
  {"id":47,"q":"Una Hoja de Datos de Seguridad (SDS) de un producto químico del salón te indica principalmente:","opts":["El precio de venta","El eslogan publicitario de la marca","La hora de la cita del cliente","Los peligros del producto, su manejo seguro y las medidas de primeros auxilios"],"re":"Una SDS enumera los peligros de cada producto, su manejo y almacenamiento, y los primeros auxilios y la respuesta ante derrames, y debe estar accesible para los empleados."},
  {"id":48,"q":"Durante una inspección de rutina de la Junta, el inspector verificará con mayor probabilidad que:","opts":["El volumen de la música sea bajo","Se cumplan las reglas de desinfección y saneamiento","Las sillas combinen con las paredes","El personal sea amable"],"re":"Los inspectores se centran en el cumplimiento de los requisitos de saneamiento y desinfección, que están entre las infracciones más comúnmente citadas."},
  {"id":49,"q":"Si un implemento que no puede limpiarse ni desinfectarse correctamente (es poroso o de un solo uso) se ha usado con un cliente, las reglas exigen que:","opts":["Lo reutilices con el siguiente cliente","Lo guardes con las herramientas desinfectadas","Lo compartas entre clientes","Lo deseches tras ese único uso"],"re":"Los artículos que no pueden limpiarse ni desinfectarse deben ser de un solo uso y desecharse; las reglas no permiten reutilizarlos con otras personas."},
  {"id":50,"q":"Para proteger a un cliente antes de un color derivado de anilina o un servicio químico, el profesional con licencia debe:","opts":["Omitir todas las pruebas para ahorrar tiempo","Usar la fórmula más fuerte disponible","Realizar las pruebas adecuadas (como una prueba de parche) y revisar las sensibilidades del cliente","Evitar preguntar por reacciones previas"],"re":"Verificar las sensibilidades, incluida una prueba de parche cuando corresponda, ayuda a prevenir reacciones alérgicas y protege al cliente."}
];
